def simple_encrypt(text):
    mapping = {'a': 'b', 'b': 'c', 'c': 'd', 'd': 'e', 'e': 'f', 'f': 'g', 'g': 'h', 'h': 'i', 'i': 'j', 'j': 'k', 'k': 'l', 'l': 'm', 'm': 'n', 'n': 'o', 'o': 'p', 'p': 'q', 'q': 'r', 'r': 's', 's': 't', 't': 'u', 'u': 'v', 'v': 'w', 'w': 'x', 'x': 'y', 'y': 'z', 'z': 'a'}
    result = ''
    for char in text.lower():
        result += mapping.get(char, char)
    return result

def shift_encrypt(text, shift=3):
    result = ''
    for char in text:
        if char.isalpha():
            base = ord('A') if char.isupper() else ord('a')
            result += chr((ord(char) - base + shift) % 26 + base)
        else:
            result += char
    return result

def reverse_encrypt(text):
    return text[::-1]

def main():
    text = "Hello World!"
    print(f"原始文本: {text}")
    print(f"简单加密: {simple_encrypt(text)}")
    print(f"位移加密: {shift_encrypt(text, 3)}")
    print(f"反向加密: {reverse_encrypt(text)}")

main()

