import time

def timer(func):
    def wrapper(*args, **kwargs):
        start = time.time()
        result = func(*args, **kwargs)
        end = time.time()
        print(f"{func.__name__}执行时间: {end - start:.4f}秒")
        return result
    return wrapper

@timer
def slow_function():
    time.sleep(0.5)
    print("函数执行完毕")

@timer
def calculate_sum(n):
    return sum(range(n))

slow_function()
calculate_sum(1000000)

def validate_positive(func):
    def wrapper(*args):
        for arg in args:
            if not isinstance(arg, (int, float)) or arg <= 0:
                raise ValueError(f"参数{arg}必须为正数")
        return func(*args)
    return wrapper

