class Calculator:
    def __init__(self):
        self.operations = {
            'add': lambda a, b: a + b,
            'subtract': lambda a, b: a - b,
            'multiply': lambda a, b: a * b,
            'divide': lambda a, b: a / b if b != 0 else None
        }

    def calculate(self, operation, a, b):
        if operation in self.operations:
            return self.operations[operation](a, b)
        else:
            return None

