def memoized_fibonacci():
    cache = {}

    def fibonacci(n):
        if n <= 0:
            return 0
        elif n == 1:
            return 1
        elif n in cache:
            return cache[n]
        else:
            result = fibonacci(n - 1) + fibonacci(n - 2)
            cache[n] = result
            return result

    return fibonacci

fib = memoized_fibonacci()
print(f"斐波那契第10项: {fib(10)}")
print(f"斐波那契第20项: {fib(20)}")
print(f"斐波那契第30项: {fib(30)}")
